import {createProxy,meta,kill}
from "./from-bootloader.js";

export async function main(...args){
  const [o,a]=this.collectOptions(args);
  if(o.l){
    for(let m of meta()){
      this.echo(m.id,m.main);
    }
    return ;
  }
  if(o.kill){
    const k=kill(o.kill);
    if(k){
      
      return ;
    }
    for(let m of meta()){
      this.echo(m.id,m.main);
      this.echo("worker","-kill="+m.id);
    }
    return ;
  }
  const p=await createProxy(a[0],o.rev||{});
  const m=meta(p);
  Object.assign(m,o);
  return p;
}